using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Look up a configuration value by key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up")] string key)
    {
        var store = ConfigStore.Current;
        return store.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", store.Keys)}";
    }

    [McpServerTool, Description("Set a configuration value.")]
    public static string SetConfigValue(
        [Description("The configuration key")] string key,
        [Description("The value to set")] string value)
    {
        ConfigStore.Current[key] = value;
        return $"Set {key} = {value}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/all",
        Name = "All Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllConfig() =>
        JsonSerializer.Serialize(ConfigStore.Current, ConfigStore.SerializerOptions);

    [McpServerResource(
        UriTemplate = "config://app/environment",
        Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironment() =>
        JsonSerializer.Serialize(new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessId = Environment.ProcessId
        }, ConfigStore.SerializerOptions);
}

using System.Collections.Concurrent;
using System.Text.Json;

/// <summary>Simple in-memory configuration store shared across tools and resources.</summary>
public static class ConfigStore
{
    public static ConcurrentDictionary<string, string> Current { get; } = new(
        new Dictionary<string, string>
        {
            ["app:name"] = "ConfigMcpServer",
            ["app:version"] = "1.0.0",
            ["app:environment"] = "Development",
            ["feature:dark-mode"] = "true",
            ["feature:beta-access"] = "false"
        });

    public static JsonSerializerOptions SerializerOptions { get; } = new()
    {
        WriteIndented = true
    };
}

